+    #[test]
+    fn test_memory_bind_pager_publication_uses_synthetic_commit_clock_snapshot() {
+        let conn = Connection::open(":memory:").unwrap();
+        let cx = conn.op_cx().unwrap();
+
+        let publication = conn
+            .bind_pager_publication(&cx, "autocommit_begin")
+            .unwrap();
+
+        assert_eq!(
+            publication.source,
+            super::PagerPublicationSource::SyntheticMemory
+        );
+        assert_eq!(publication.snapshot.snapshot_gen, 0);
+        assert_eq!(
+            publication.snapshot.visible_commit_seq,
+            conn.current_global_commit_seq(),
+            "synthetic memory publications should bind from the finalized connection-local commit clock"
+        );
+        let pager_snapshot = conn.pager.published_snapshot();
+        assert_eq!(
+            publication.snapshot.journal_mode,
+            pager_snapshot.journal_mode
+        );
+        assert_eq!(publication.snapshot.db_size, pager_snapshot.db_size);
+        assert_eq!(
+            publication.snapshot.freelist_count,
+            pager_snapshot.freelist_count
+        );
+        assert_eq!(
